import React from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { useAuth } from './context/AuthContext';
import './App.css';

import Navbar from './components/Navbar';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';
import PortfolioPage from './pages/PortfolioPage';
import RegisterPage from './pages/RegisterPage';

const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col items-center justify-center font-mono">
      <div className="w-10 h-10 border-2 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin mb-4" />
      <p className="text-emerald-500 text-[10px] tracking-[0.4em] animate-pulse uppercase">decrypting_node...</p>
    </div>
  );

  return user ? children : <Navigate to="/login" state={{ from: location }} replace />;
};

function App() {
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-mono selection:bg-emerald-500 selection:text-black">
      <Toaster 
        position="bottom-right"
        toastOptions={{
          style: { background: '#141414', color: '#fff', border: '1px solid #10b98133', fontSize: '11px', fontFamily: 'monospace' },
          success: { iconTheme: { primary: '#10b981', secondary: '#141414' } },
        }}
      />
      <Navbar />
      <main className="container mx-auto px-4 py-8">
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/dashboard" element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} />
          <Route path="/generate" element={<ProtectedRoute><GeneratePage /></ProtectedRoute>} />
          <Route path="/portfolio/:id" element={<ProtectedRoute><PortfolioPage /></ProtectedRoute>} />
          <Route path="*" element={<Navigate to="/dashboard" replace />} />
        </Routes>
      </main>
    </div>
  );
}

export default App;
